-- 0020: Comprehensive Greek-city coverage. Adds 65 new cities so the
-- citynight.gr guide covers all of Greece (mainland + every inhabited island
-- with tourism relevance). Total cities after this migration: ~99.
--
-- Photos: only inserted where the Pexels alt-text explicitly contains the
-- city name (strict match). Loose-match cities are added WITHOUT a hero —
-- the styled placeholder renders until a hand-picked photo is available.
-- (Integrity rule: never put a generic Greek shot under a specific city.)
--
-- Re-runnable: clears all 0020 rows up front.

DELETE FROM photos WHERE id LIKE 'photo_seed20_%';
DELETE FROM translations WHERE id LIKE 'tr_seed20_%';
DELETE FROM cities WHERE id LIKE 'city_seed20_%';

